//precalculating lookup-tables what C preprocessor cannot do unfortunately, and we don't want to call an init() function to do so

#include <stdio.h>

#include <math.h>


#include "fixedpoint.h"


#define PI 3.14159 //22.0/7.0 = 3.14285
#define RAD (PI/180.0)

#define ARRAYNAME_PREFIX "static const u8 " FIXEDPOINT_PREFIX
#define NEWLINE_COLUMN 16 //table-value positions


int main () {
 double Value; int i, TableValue;
 FILE *OutputFile, *RawFile;

 OutputFile = fopen( "tables.c", "w" ); fputs( "//Precalculated fixed-point lookup-tables generated by precalc.c\n\n", OutputFile );
 if (OutputFile == NULL) { printf( "Couldn't create output-file!\n" ); return -1; }
 RawFile = fopen( "tables.raw", "wb" );

 //printf("Square-root lookup-table:\n");
 fprintf( OutputFile, ARRAYNAME_PREFIX "SquareRootTable [] = { //integer part: upper %d bits, fractional part: lower %d bits\n ", FIXEDPOINT_SQRT_TABLEVALUE_INTEGER_BITS, FIXEDPOINT_TABLEVALUE_FRACTIONAL_BITS );
 for (i=0; i < FIXEDPOINT_TABLE_SIZE; ++i) { //SquareRoot
  /*Value = sqrt(i*256);*/ TableValue = round(sqrt(i*256)); //(int)round(Value * FIXEDPOINT_TABLEVALUE_FRACTIONAL_RANGE); //printf( "%.2f->$%2.2X ", Value, TableValue );
  fprintf( OutputFile, "0x%2.2X,", TableValue ); if ((i+1) % NEWLINE_COLUMN == 0) fprintf( OutputFile, "\n " );
  if (RawFile != NULL) fputc( TableValue, RawFile );
 }
 fprintf( OutputFile, "0x00,\n};\n\n" );

 //printf("Sine-wave lookup-table:\n");
 fprintf( OutputFile, ARRAYNAME_PREFIX "SineTable [] = { //(a quarter sine, magnitude: %d)\n ", FIXEDPOINT_TABLEVALUE_RANGE );
 for (i=0; i < FIXEDPOINT_SINE_TABLE_SIZE; ++i) { //Sine
  TableValue = round( sin(i/4.0 * RAD) * FIXEDPOINT_TABLEVALUE_MAX );
  fprintf( OutputFile, "0x%2.2X,", TableValue ); if ((i+1) % NEWLINE_COLUMN == 0) fprintf( OutputFile, "\n " );
  if (RawFile != NULL) fputc( TableValue, RawFile );
 }
 fprintf( OutputFile, "\n0x00,\n};\n\n" );

 fclose( OutputFile ); if (RawFile != NULL) fclose( RawFile );  printf("\n");
 return 0;
}

